import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { LineChart } from '@mui/x-charts';
import response from './response.json';

interface RoomTemperature {
  room: string;
  temperature: number;
}

interface EnergyUsage {
  current: number;
  unit: string;
}

interface WidgetData {
  connectedDevices: number;
  energyUsage: EnergyUsage;
  roomTemperatures: RoomTemperature[];
  temperatureTrend: number[];
}

export default function Widget() {
  const widgetData = response.data as WidgetData;
  const { connectedDevices, energyUsage, roomTemperatures, temperatureTrend } = widgetData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1 }}>
              Smart Home Overview
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 0.5 }}>
              Connected Devices: {connectedDevices}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Energy Usage: {energyUsage.current} {energyUsage.unit}
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" fontWeight={600} sx={{ mb: 1 }}>
              Room Temperatures
            </Typography>
            <Stack direction="row" spacing={1}>
              {roomTemperatures.slice(0, 3).map((room, index) => (
                <Box key={index}>
                  <Typography variant="caption" color="text.secondary">
                    {room.room}
                  </Typography>
                  <Typography variant="body2">
                    {room.temperature}°F
                  </Typography>
                </Box>
              ))}
            </Stack>
          </Box>

          <LineChart
            height={100}
            series={[
              {
                data: temperatureTrend,
                color: '#4CAF50',
                showMark: false,
              },
            ]}
            xAxis={[{ data: temperatureTrend.map((_, i) => i), hide: true }]}
            margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
            sx={{
              '& .MuiLineElement-root': {
                strokeWidth: 1.5,
              },
            }}
          />
        </Stack>
      </CardContent>
    </Card>
  );
}
